function hide(n){n=n.length?n:[n];for(var i=0;i<n.length;i++)n[i].style.display="none"}async function expandMenu(){var n=document.getElementsByClassName("mud-nav-link","mud-ripple","active")[0].parentElement.getAttribute("aria-label");alert(n)}async function playAudio(n){n=document.getElementById(n);null!=n&&n.play()}async function pauseAudio(n){n=document.getElementById(n);null!=n&&n.pause()}async function requestNotificationPermission(){await Notification.requestPermission().then(function(n){"granted"===n?console.warn("Notification permission granted."):console.warn("Notification permission denied.")})}window.notify=async function(n,i){"Notification"in window?"granted"===Notification.permission?new Notification(n,i):"denied"!==Notification.permission?"granted"===await Notification.requestPermission()?new Notification(n,i):console.warn("Notification permission denied or dismissed."):console.warn("Notifications denied permanently."):console.warn("This browser does not support notifications.")},window.setAppBadge=async function(n){"setAppBadge"in navigator?(n?await navigator.setAppBadge(n):await navigator.setAppBadge(),alert("App badge set to "+n)):console.warn("Badging API not supported.")},window.clearAppBadge=async function(){"clearAppBadge"in navigator&&await navigator.clearAppBadge()};